'use client';

import { useEffect, useState } from 'react';
import { FeedConfig } from '@/lib/bonafied/types';

const CATEGORY_OPTIONS = [
  { label: 'Business', value: 'BUSINESS' },
  { label: 'Technology', value: 'TECHNOLOGY' },
  { label: 'Music Industry', value: 'MUSIC_INDUSTRY' },
  { label: 'Podcast / Creator', value: 'PODCAST_CREATOR' }
] as const;

export default function AdminPage() {
  const [feeds, setFeeds] = useState<FeedConfig[]>([]);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState('');
  const [form, setForm] = useState({
    name: '',
    url: '',
    category: 'BUSINESS',
    credibilityScore: 0.75,
    active: true
  });

  const loadFeeds = async () => {
    const response = await fetch('/api/feeds', { cache: 'no-store' });
    const data = await response.json();
    setFeeds(data.feeds || []);
  };

  useEffect(() => {
    void (async () => {
      setLoading(true);
      try {
        await loadFeeds();
      } finally {
        setLoading(false);
      }
    })();
  }, []);

  const createFeed = async () => {
    setMessage('Saving feed...');
    const response = await fetch('/api/feeds', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        ...form,
        credibilityScore: Number(form.credibilityScore)
      })
    });

    if (!response.ok) {
      const data = await response.json();
      setMessage(data.error || 'Could not add feed');
      return;
    }

    await loadFeeds();
    setMessage('Feed added.');
    setForm({
      name: '',
      url: '',
      category: form.category,
      credibilityScore: 0.75,
      active: true
    });
  };

  const toggleFeedActive = async (feed: FeedConfig) => {
    await fetch(`/api/feeds/${feed.id}`, {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ active: !feed.active })
    });

    await loadFeeds();
  };

  const runIngestion = async () => {
    setMessage('Running ingestion...');
    const response = await fetch('/api/ingest', {
      method: 'POST'
    });
    const data = await response.json();
    setMessage(
      `Ingestion complete: +${data.ingestedStories || 0} stories, ${data.clusteredSignals || 0} clusters (${data.ingestedAt}).`
    );
  };

  return (
    <div className="admin-wrap">
      <h1 style={{ fontSize: 32, marginTop: 0, letterSpacing: '-0.02em' }}>BONAFIED Admin</h1>
      <p style={{ color: 'var(--text-secondary)', marginTop: 8 }}>
        Configure RSS feeds and run ingestion for THE WIRE.
      </p>

      <section className="admin-card" style={{ marginTop: 18 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 10 }}>
          <h2 style={{ margin: 0, fontSize: 18 }}>Feed Configuration</h2>
          <button className="small-btn primary" onClick={() => void runIngestion()}>
            Ingest Now
          </button>
        </div>

        <div className="admin-form">
          <input
            placeholder="Feed Name"
            value={form.name}
            onChange={(event) => setForm((current) => ({ ...current, name: event.target.value }))}
          />
          <input
            placeholder="RSS URL"
            value={form.url}
            onChange={(event) => setForm((current) => ({ ...current, url: event.target.value }))}
          />

          <select
            value={form.category}
            onChange={(event) => setForm((current) => ({ ...current, category: event.target.value as typeof form.category }))}
          >
            {CATEGORY_OPTIONS.map((option) => (
              <option key={option.value} value={option.value}>
                {option.label}
              </option>
            ))}
          </select>

          <input
            type="number"
            min="0"
            max="1"
            step="0.01"
            value={form.credibilityScore}
            onChange={(event) =>
              setForm((current) => ({
                ...current,
                credibilityScore: Number(event.target.value)
              }))
            }
          />
        </div>

        <div style={{ marginTop: 10 }}>
          <button className="small-btn" onClick={() => void createFeed()}>
            Add Feed
          </button>
        </div>

        {message ? <div style={{ marginTop: 12, color: 'var(--text-secondary)', fontSize: 13 }}>{message}</div> : null}

        {loading ? (
          <div style={{ marginTop: 18, color: 'var(--text-tertiary)' }}>Loading feeds...</div>
        ) : (
          <table className="admin-table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Category</th>
                <th>Credibility</th>
                <th>Active</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {feeds.map((feed) => (
                <tr key={feed.id}>
                  <td>
                    {feed.name}
                    <div style={{ color: 'var(--text-tertiary)', fontSize: 11, marginTop: 4 }}>{feed.url}</div>
                  </td>
                  <td>{feed.category}</td>
                  <td>{feed.credibilityScore.toFixed(2)}</td>
                  <td>{feed.active ? 'Yes' : 'No'}</td>
                  <td>
                    <button className="small-btn" onClick={() => void toggleFeedActive(feed)}>
                      {feed.active ? 'Disable' : 'Enable'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </section>
    </div>
  );
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

export const runtime = 'nodejs';

const requestSchema = z.object({
  prompt: z.string().trim().min(1).max(30000),
  model: z.string().trim().min(1).max(120).default('claude-sonnet-4-20250514'),
  maxTokens: z.number().int().positive().max(4096).default(1200),
  apiKey: z.string().trim().max(300).optional().default('')
});

export async function POST(req: NextRequest) {
  const payload = await req.json().catch(() => null);
  const parsed = requestSchema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid AI payload', details: parsed.error.issues }, { status: 400 });
  }

  const { prompt, model, maxTokens, apiKey } = parsed.data;
  const key = (apiKey || process.env.ANTHROPIC_API_KEY || '').trim();
  if (!key) {
    return NextResponse.json({ error: 'Missing Anthropic API key.' }, { status: 400 });
  }

  try {
    const upstream = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': key,
        'anthropic-version': '2023-06-01'
      },
      body: JSON.stringify({
        model,
        max_tokens: maxTokens,
        messages: [{ role: 'user', content: prompt }]
      })
    });

    const raw = await upstream.text();
    if (!upstream.ok) {
      let msg = `Anthropic error ${upstream.status}`;
      try {
        const parsedError = JSON.parse(raw) as { error?: { message?: string } };
        msg = parsedError?.error?.message || msg;
      } catch {}
      return NextResponse.json({ error: msg }, { status: upstream.status });
    }

    const data = JSON.parse(raw) as { content?: Array<{ type?: string; text?: string }> };
    const text =
      data?.content
        ?.map((item) => (item?.type === 'text' ? item.text || '' : ''))
        .filter(Boolean)
        .join('\n') || 'No response.';

    return NextResponse.json({ ok: true, text });
  } catch (error) {
    console.error('Anthropic proxy failed', error);
    return NextResponse.json({ error: 'AI proxy request failed.' }, { status: 502 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

export const runtime = 'nodejs';

const requestSchema = z.object({
  prompt: z.string().trim().min(1).max(30000),
  model: z.string().trim().min(1).max(120).default('gpt-4.1'),
  maxTokens: z.number().int().positive().max(4096).default(1200),
  apiKey: z.string().trim().max(300).optional().default('')
});

type OpenAIResponse = {
  output_text?: string;
  output?: Array<{
    type?: string;
    content?: Array<{ type?: string; text?: string }>;
  }>;
};

function parseOpenAIResponseText(payload: OpenAIResponse): string {
  if (typeof payload?.output_text === 'string' && payload.output_text.trim()) {
    return payload.output_text.trim();
  }
  const parts: string[] = [];
  (payload?.output || []).forEach((item) => {
    if (item?.type !== 'message') return;
    (item?.content || []).forEach((content) => {
      if ((content?.type === 'output_text' || content?.type === 'text') && content?.text) {
        parts.push(content.text);
      }
    });
  });
  return parts.join('\n').trim() || 'No response.';
}

export async function POST(req: NextRequest) {
  const payload = await req.json().catch(() => null);
  const parsed = requestSchema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid AI payload', details: parsed.error.issues }, { status: 400 });
  }

  const { prompt, model, maxTokens, apiKey } = parsed.data;
  const key = (apiKey || process.env.OPENAI_API_KEY || '').trim();
  if (!key) {
    return NextResponse.json({ error: 'Missing OpenAI API key.' }, { status: 400 });
  }

  try {
    const upstream = await fetch('https://api.openai.com/v1/responses', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${key}`
      },
      body: JSON.stringify({
        model,
        input: prompt,
        max_output_tokens: maxTokens
      })
    });

    const raw = await upstream.text();
    if (!upstream.ok) {
      let msg = `OpenAI error ${upstream.status}`;
      try {
        const parsedError = JSON.parse(raw) as { error?: { message?: string } | string };
        const nested = typeof parsedError?.error === 'string' ? parsedError.error : parsedError?.error?.message;
        msg = nested || msg;
      } catch {}
      return NextResponse.json({ error: msg }, { status: upstream.status });
    }

    const data = JSON.parse(raw) as OpenAIResponse;
    const text = parseOpenAIResponseText(data);
    return NextResponse.json({ ok: true, text });
  } catch (error) {
    console.error('OpenAI proxy failed', error);
    return NextResponse.json({ error: 'AI proxy request failed.' }, { status: 502 });
  }
}

import { NextResponse } from 'next/server';

export async function POST() {
  const response = NextResponse.json({ ok: true });
  response.cookies.set('bonafied_user', '', {
    httpOnly: true,
    sameSite: 'lax',
    path: '/',
    maxAge: 0
  });
  response.cookies.set('bonafied_email', '', {
    httpOnly: true,
    sameSite: 'lax',
    path: '/',
    maxAge: 0
  });
  return response;
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { sendMagicLinkEmail } from '@/lib/bonafied/magic-link';
import { createMagicToken } from '@/lib/bonafied/repository';

const schema = z.object({
  email: z.string().email().max(220)
});

export async function POST(req: NextRequest) {
  const payload = await req.json().catch(() => null);
  const parsed = schema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid email payload', details: parsed.error.issues }, { status: 400 });
  }

  const allowed = (process.env.AR_ALLOWED_EMAILS || '')
    .split(',')
    .map((item) => item.trim().toLowerCase())
    .filter(Boolean);
  const email = parsed.data.email.toLowerCase();
  if (allowed.length > 0 && !allowed.includes(email)) {
    return NextResponse.json({ error: 'Email is not allowed for this workspace' }, { status: 403 });
  }

  const token = await createMagicToken(email);
  await sendMagicLinkEmail(email, token.token);

  const baseUrl = process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000';

  return NextResponse.json({
    ok: true,
    expiresAt: token.expiresAt,
    previewLink: `${baseUrl}/api/auth/verify?token=${token.token}`
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { consumeMagicToken } from '@/lib/bonafied/repository';

export async function GET(req: NextRequest) {
  const { searchParams } = new URL(req.url);
  const token = searchParams.get('token');

  if (!token) {
    return NextResponse.json({ error: 'Missing token' }, { status: 400 });
  }

  const session = await consumeMagicToken(token);
  if (!session) {
    return NextResponse.json({ error: 'Token invalid or expired' }, { status: 401 });
  }

  const destination = new URL('/ar', req.url);
  const response = NextResponse.redirect(destination);
  const secure = process.env.NODE_ENV === 'production';
  response.cookies.set('bonafied_user', session.userId, {
    httpOnly: true,
    secure,
    sameSite: 'lax',
    path: '/',
    maxAge: 60 * 60 * 24 * 30
  });
  response.cookies.set('bonafied_email', session.email, {
    httpOnly: true,
    secure,
    sameSite: 'lax',
    path: '/',
    maxAge: 60 * 60 * 24 * 30
  });

  return response;
}

import { NextRequest, NextResponse } from 'next/server';
import { invalidateByPrefix } from '@/lib/bonafied/cache';
import { ingestFeeds } from '@/lib/bonafied/ingest';

export const runtime = 'nodejs';

export async function POST(req: NextRequest) {
  const secret = process.env.INGEST_CRON_SECRET || process.env.CRON_SECRET || '';

  if (secret) {
    const authHeader = req.headers.get('authorization') || '';
    const xSecret = req.headers.get('x-cron-secret') || '';
    const querySecret = new URL(req.url).searchParams.get('secret') || '';

    const authorized =
      authHeader === `Bearer ${secret}` ||
      authHeader === secret ||
      xSecret === secret ||
      querySecret === secret;

    if (!authorized) {
      return NextResponse.json({ error: 'Unauthorized cron invocation' }, { status: 401 });
    }
  }

  const result = await ingestFeeds();
  await invalidateByPrefix('signals:');

  return NextResponse.json({
    ok: true,
    ...result
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { exportDossier } from '@/lib/bonafied/repository';

export async function GET(req: NextRequest, context: { params: Promise<{ id: string }> }) {
  const { id } = await context.params;
  const { searchParams } = new URL(req.url);
  const userId = searchParams.get('userId') || 'demo-user';
  const format = searchParams.get('format') === 'text' ? 'text' : 'markdown';

  const content = await exportDossier(userId, id, format);
  if (!content) {
    return NextResponse.json({ error: 'Dossier not found' }, { status: 404 });
  }

  const filename = `dossier-${id}.${format === 'markdown' ? 'md' : 'txt'}`;

  return new NextResponse(content, {
    status: 200,
    headers: {
      'Content-Type': format === 'markdown' ? 'text/markdown; charset=utf-8' : 'text/plain; charset=utf-8',
      'Content-Disposition': `attachment; filename=\"${filename}\"`
    }
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { addStoryToDossier, createDossier, getDossiers } from '@/lib/bonafied/repository';

const createSchema = z.object({
  name: z.string().min(2).max(120),
  notes: z.string().max(2000).optional(),
  storyIds: z.array(z.string()).optional()
});

const addStorySchema = z.object({
  dossierId: z.string().min(4),
  storyId: z.string().min(4)
});

export async function GET(req: NextRequest) {
  const { searchParams } = new URL(req.url);
  const userId = searchParams.get('userId') || 'demo-user';
  const dossiers = await getDossiers(userId);
  return NextResponse.json({
    dossiers
  });
}

export async function POST(req: NextRequest) {
  const { searchParams } = new URL(req.url);
  const userId = searchParams.get('userId') || 'demo-user';
  const mode = searchParams.get('mode') || 'create';

  const payload = await req.json().catch(() => null);
  if (mode === 'add-story') {
    const parsed = addStorySchema.safeParse(payload);
    if (!parsed.success) {
      return NextResponse.json({ error: 'Invalid add-story payload', details: parsed.error.issues }, { status: 400 });
    }

    const dossier = await addStoryToDossier(userId, parsed.data.dossierId, parsed.data.storyId);
    if (!dossier) {
      return NextResponse.json({ error: 'Dossier not found' }, { status: 404 });
    }

    return NextResponse.json({ dossier });
  }

  const parsed = createSchema.safeParse(payload);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid dossier payload', details: parsed.error.issues }, { status: 400 });
  }

  const dossier = await createDossier(userId, parsed.data);
  return NextResponse.json({ dossier }, { status: 201 });
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { updateFeed } from '@/lib/bonafied/repository';

const patchSchema = z.object({
  name: z.string().min(2).max(120).optional(),
  url: z.string().url().max(500).optional(),
  category: z.enum(['BUSINESS', 'TECHNOLOGY', 'MUSIC_INDUSTRY', 'PODCAST_CREATOR']).optional(),
  credibilityScore: z.number().min(0).max(1).optional(),
  active: z.boolean().optional()
});

export async function PATCH(req: NextRequest, context: { params: Promise<{ id: string }> }) {
  const { id } = await context.params;
  const payload = await req.json().catch(() => null);
  const parsed = patchSchema.safeParse(payload);

  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid feed patch', details: parsed.error.issues }, { status: 400 });
  }

  const updated = await updateFeed(id, parsed.data);
  if (!updated) {
    return NextResponse.json({ error: 'Feed not found' }, { status: 404 });
  }

  return NextResponse.json({ feed: updated });
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { addFeed, getFeeds } from '@/lib/bonafied/repository';

const createFeedSchema = z.object({
  name: z.string().min(2).max(120),
  url: z.string().url().max(500),
  category: z.enum(['BUSINESS', 'TECHNOLOGY', 'MUSIC_INDUSTRY', 'PODCAST_CREATOR']),
  credibilityScore: z.number().min(0).max(1).default(0.7),
  active: z.boolean().default(true)
});

export async function GET() {
  const feeds = await getFeeds();
  return NextResponse.json({
    feeds
  });
}

export async function POST(req: NextRequest) {
  const payload = await req.json().catch(() => null);
  const parsed = createFeedSchema.safeParse(payload);

  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid feed payload', details: parsed.error.issues }, { status: 400 });
  }

  const feed = await addFeed(parsed.data);
  return NextResponse.json({ feed }, { status: 201 });
}

