  const [commandOpen, setCommandOpen] = useState(false);
  const [commandQuery, setCommandQuery] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState<SearchResult[]>([]);
  const [cursorIndex, setCursorIndex] = useState(0);
  const [magicEmail, setMagicEmail] = useState('');
  const [magicMessage, setMagicMessage] = useState('');
  const [dossiers, setDossiers] = useState<Dossier[]>(initialDossiers);
  const [newSignalCount, setNewSignalCount] = useState(initialPayload.newSignalCount || 0);
  const [liveCounter, setLiveCounter] = useState(initialPayload.live.ingestCounter);

  const filedSet = useMemo(() => new Set(payload.filedStoryIds), [payload.filedStoryIds]);

  const allStories = useMemo(() => {
    const map = new Map<string, StoryWithCluster>();
    if (payload.hero) {
      map.set(payload.hero.id, payload.hero);
    }

    for (const row of payload.rows) {
      for (const story of row.stories) {
        if (!map.has(story.id)) {
          map.set(story.id, story);
        }
      }
    }

    return [...map.values()];
  }, [payload]);

  const selectedStory =
    allStories.find((story) => story.id === selectedStoryId) || payload.hero || allStories[0] || null;

  useEffect(() => {
    document.body.dataset.accent = preferences.accent;
  }, [preferences.accent]);

  useEffect(() => {
    if (!selectedStoryId && payload.hero) {
      setSelectedStoryId(payload.hero.id);
    }
  }, [payload.hero, selectedStoryId]);

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      const target = event.target as HTMLElement;
      const typingTarget = target?.tagName === 'INPUT' || target?.tagName === 'TEXTAREA';

      if ((event.metaKey || event.ctrlKey) && event.key.toLowerCase() === 'k') {
        event.preventDefault();
        setCommandOpen(true);
        return;
      }

      if (commandOpen || typingTarget) {
        return;
      }

      if (event.key.toLowerCase() === 'j') {
        event.preventDefault();
        moveCursor(1);
        return;
      }

      if (event.key.toLowerCase() === 'k') {
        event.preventDefault();
        moveCursor(-1);
        return;
      }

      if (event.key === 'Enter') {
        event.preventDefault();
        const focused = allStories[cursorIndex];
        if (focused) {
          setSelectedStoryId(focused.id);
        }
        return;
      }

      if (event.key.toLowerCase() === 's' && selectedStory) {
        event.preventDefault();
        void toggleFiled(selectedStory.id);
      }
    };

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [commandOpen, allStories, cursorIndex, selectedStory]);

  useEffect(() => {
    const id = window.setInterval(() => {
      void pollLiveMeta();
    }, 30_000);

    return () => window.clearInterval(id);
  }, [liveCounter]);

  useEffect(() => {
    if (!commandOpen) {
      setCommandQuery('');
      setSearchResults([]);
    }
  }, [commandOpen]);

  useEffect(() => {
    const trimmed = commandQuery.trim();
    if (!trimmed) {
      setSearchResults([]);
      return;
    }

    const timeout = window.setTimeout(async () => {
      try {
        const response = await fetch(
          `/api/signals/search?q=${encodeURIComponent(trimmed)}&channel=${encodeURIComponent(channel)}`,
          {
            cache: 'no-store'
          }
        );
        const data = await response.json();
        setSearchResults(data.results || []);
      } catch {
        setSearchResults([]);
      }
    }, 160);

    return () => window.clearTimeout(timeout);
  }, [commandQuery, channel]);

  const moveCursor = (delta: number) => {
    if (!allStories.length) {
      return;
    }
    const next = (cursorIndex + delta + allStories.length) % allStories.length;
    setCursorIndex(next);
    setSelectedStoryId(allStories[next].id);
  };

  const refreshSignals = async (
    nextChannel: Channel,
    options?: {
      q?: string;
      only24h?: boolean;
    }
  ) => {
    setLoading(true);

    try {
      const timezone = preferences.timezone || DEFAULT_TIMEZONE;
      const only24h = options?.only24h ?? preferences.only24h;
      const query = options?.q ?? searchTerm;

      const response = await fetch(
        `/api/signals?channel=${encodeURIComponent(nextChannel)}&timezone=${encodeURIComponent(timezone)}&only24h=${only24h}&userId=${encodeURIComponent(userId)}&q=${encodeURIComponent(query)}`,
        {
          cache: 'no-store'
        }
      );

      const data = (await response.json()) as SignalPayload;
      setPayload(data);
      setNewSignalCount(data.newSignalCount || data.live.recentCount || 0);
      setLiveCounter(data.live.ingestCounter);

      const currentSelected = data.hero || data.rows[0]?.stories[0];
      if (currentSelected) {
        const stillExists = [data.hero, ...data.rows.flatMap((row) => row.stories)].some(
          (story) => story?.id === selectedStoryId
        );
        if (!stillExists) {
          setSelectedStoryId(currentSelected.id);
          setCursorIndex(0);
        }
      }
    } finally {
      setLoading(false);
    }
  };

  const pollLiveMeta = async () => {
    try {
      const response = await fetch('/api/signals/live', { cache: 'no-store' });
      const live = await response.json();

      if (live.ingestCounter > liveCounter) {
        setNewSignalCount(Math.max(live.recentCount || 0, 1));
      }
    } catch {
      // noop
    }
  };

  const patchPreferences = async (next: Partial<Omit<UserPreferences, 'userId'>>) => {
    const response = await fetch(`/api/preferences?userId=${encodeURIComponent(userId)}`, {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(next)
    });

    const data = await response.json();
    const updated = data.preferences as UserPreferences;
    setPreferences(updated);
    return updated;
  };

  const toggleFiled = async (storyId: string) => {
    const filed = !filedSet.has(storyId);
    const response = await fetch(`/api/filed?userId=${encodeURIComponent(userId)}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ storyId, filed })
    });
    const data = await response.json();

    setPayload((current) => ({
      ...current,
      filedStoryIds: (data.filed || []).map((item: { storyId: string }) => item.storyId)
    }));
  };

  const createDossierFromSelected = async () => {
    if (!selectedStory) {
      return;
    }
    const name = window.prompt('Dossier name');
    if (!name) {
      return;
    }

    const response = await fetch(`/api/dossiers?userId=${encodeURIComponent(userId)}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        name,
        storyIds: [selectedStory.id],
        notes: `Created from THE WIRE on ${new Date().toISOString()}`
      })
    });

    const data = await response.json();
    if (data.dossier) {
      setDossiers((current) => [data.dossier, ...current]);
    }
  };

  const addSelectedToDossier = async (dossierId: string) => {
    if (!selectedStory) {
      return;
    }

    const response = await fetch(`/api/dossiers?userId=${encodeURIComponent(userId)}&mode=add-story`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        dossierId,
        storyId: selectedStory.id
      })
    });

    const data = await response.json();
    if (data.dossier) {
      setDossiers((current) => current.map((dossier) => (dossier.id === data.dossier.id ? data.dossier : dossier)));
    }
  };

  const requestMagicLink = async () => {
    if (!magicEmail) {
      return;
    }

    setMagicMessage('Sending magic link...');

    try {
      const response = await fetch('/api/auth/request-link', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ email: magicEmail })
      });

      const data = await response.json();
      if (response.ok) {
        setMagicMessage(`Magic link sent. Preview: ${data.previewLink}`);
      } else {
        setMagicMessage(data.error || 'Could not send magic link');
      }
    } catch {
      setMagicMessage('Could not send magic link');
    }
  };

  const onSelectCommandResult = (result: SearchResult) => {
    if (result.type === 'story') {
      setSelectedStoryId(result.id);
      const index = allStories.findIndex((story) => story.id === result.id);
      if (index >= 0) {
        setCursorIndex(index);
      }
    }

    setCommandOpen(false);
  };

  const toggle24Hour = async () => {
    const nextValue = !preferences.only24h;
    const updated = await patchPreferences({ only24h: nextValue });
    await refreshSignals(channel, { only24h: updated.only24h });
  };

  const setAccent = async () => {
    const nextAccent = preferences.accent === 'cobalt' ? 'amber' : 'cobalt';
    await patchPreferences({ accent: nextAccent });
  };

  const onChangeChannel = async (next: Channel) => {
    setChannel(next);
    await refreshSignals(next);
  };

  const applySearch = async () => {
    await refreshSignals(channel, { q: searchTerm });
  };

  return (
    <LayoutGroup>
      <div className="bonafied-root">
        <header className="glass topbar">
          <div className="brand">
            <BrainFireLogo size={22} />
            BONAFIED
          </div>

          <nav className="topbar-center" aria-label="Channels">
            {CHANNEL_ORDER.map((item) => (
              <button
                key={item}
                className={`nav-chip ${channel === item ? 'active' : ''}`}
                onClick={() => {
                  void onChangeChannel(item);
                }}
              >
                {CHANNEL_LABELS[item]}
              </button>
            ))}
          </nav>

          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <button className="command-trigger" onClick={() => setCommandOpen(true)}>
              <Search size={15} />
              Search THE WIRE
              <span className="kbd">⌘K</span>
            </button>

            <button
              className="small-btn"
              onClick={() => {
                void setAccent();
              }}
            >
              Accent: {preferences.accent === 'cobalt' ? 'Cobalt' : 'Amber'}
            </button>

            <div className="live-pill" title={`Last ingest: ${formatTimestamp(payload.live.lastIngestAt, preferences.timezone)}`}>
              <span className="live-dot" />
              {newSignalCount > 0 ? `${newSignalCount} new signals` : 'THE WIRE synced'}
              {newSignalCount > 0 ? (
                <button
                  className="ghost-btn"
                  onClick={() => {
                    setNewSignalCount(0);
                    void refreshSignals(channel);
                  }}
                >
                  Refresh
                </button>
              ) : null}
            </div>
          </div>
        </header>

        <aside className="glass sidebar">
          <section>
            <div className="panel-title">Dossier</div>
            <button className={`side-item ${channel === 'TODAY' ? 'active' : ''}`} onClick={() => void onChangeChannel('TODAY')}>
              <Rss size={16} />
              <span>The Wire</span>
            </button>
            <button className="side-item" onClick={() => selectedStory && void toggleFiled(selectedStory.id)}>
              <Bookmark size={16} />
              <span className={selectedStory && filedSet.has(selectedStory.id) ? 'filed' : ''}>Filed</span>
            </button>
            <button className="side-item" onClick={createDossierFromSelected}>
              <FolderClosed size={16} />
              <span>Dossier</span>
              <span className="side-meta">{dossiers.length}</span>
            </button>
          </section>

          <section>
            <div className="panel-title">Channels</div>
            {CHANNEL_ORDER.filter((item) => item !== 'TODAY').map((item) => (
              <button
                key={item}
                className={`side-item ${channel === item ? 'active' : ''}`}
                onClick={() => {
                  void onChangeChannel(item);
                }}
              >
                <Sparkles size={15} />
                <span>{CHANNEL_LABELS[item]}</span>
              </button>
            ))}
          </section>

          <section>
            <div className="panel-title">Filters</div>
            <div className="toggle">
              <span>Strict last 24h</span>
              <button onClick={() => void toggle24Hour()}>{preferences.only24h ? 'ON' : 'OFF'}</button>
            </div>

            <div className="toggle" style={{ marginTop: 10 }}>
              <span>Timezone</span>
              <span>{preferences.timezone}</span>
            </div>

            <div className="toggle" style={{ marginTop: 10, flexDirection: 'column', alignItems: 'stretch', gap: 8 }}>
              <span style={{ width: '100%' }}>THE WIRE Search</span>
              <div style={{ display: 'flex', gap: 8 }}>
                <input
                  style={{
                    flex: 1,
                    borderRadius: 10,
                    border: '1px solid rgba(255,255,255,0.14)',
                    background: 'rgba(255,255,255,0.04)',
                    color: 'var(--text-primary)',
                    padding: '8px 10px',
                    fontSize: 12
                  }}
                  placeholder="Entity, source, topic"
                  value={searchTerm}
                  onChange={(event) => setSearchTerm(event.target.value)}
                />
                <button className="small-btn" onClick={() => void applySearch()}>
                  Go
                </button>
              </div>
            </div>
          </section>

          <section>
            <div className="panel-title">Magic Link</div>
            <div style={{ display: 'flex', gap: 8 }}>
              <input
                value={magicEmail}
                onChange={(event) => setMagicEmail(event.target.value)}
                placeholder="Email"
                style={{
                  flex: 1,
                  borderRadius: 10,
                  border: '1px solid rgba(255,255,255,0.14)',
                  background: 'rgba(255,255,255,0.04)',
                  color: 'var(--text-primary)',
                  padding: '8px 10px',
                  fontSize: 12
                }}
              />
              <button className="small-btn" onClick={() => void requestMagicLink()}>
                Send
              </button>
            </div>
            {magicMessage ? <div style={{ marginTop: 8, color: 'var(--text-tertiary)', fontSize: 11 }}>{magicMessage}</div> : null}
          </section>
        </aside>

        <main className="glass feed-panel">
          <AnimatePresence mode="wait">
            <motion.div
              key={channel}
              initial={{ opacity: 0, x: 42 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -42 }}
              transition={{ duration: 0.32, ease: [0.22, 0.61, 0.36, 1] }}
            >
              {payload.hero ? (
                <section className="hero-wrap fade-slide">
                  <div className="hero-label">Certified Top Story</div>
                  <motion.h1 layoutId={`story-title-${payload.hero.cluster.id}`} className="hero-title">
                    {payload.hero.title}
                  </motion.h1>
                  <div className="hero-meta">
                    <span className="hero-badge">{CHANNEL_LABELS[payload.hero.category]}</span>
                    <span>{payload.hero.sourceName}</span>
                    <span>{formatTimestamp(payload.hero.publishedAt, preferences.timezone)}</span>
                    <span>{relativeTime(payload.hero.publishedAt)}</span>
                    <span>Cluster {payload.hero.cluster.storyIds.length}</span>
                  </div>
                  {payload.hero.imageUrl ? (
                    <img className="hero-image" src={payload.hero.imageUrl} alt="Hero story" loading="eager" />
                  ) : null}
                </section>
              ) : null}

              {loading ? (
                <section className="row-shell">
                  <div className="row-track">
                    <div className="skeleton skeleton-row" />
                    <div className="skeleton skeleton-row" />
                    <div className="skeleton skeleton-row" />
                  </div>
                </section>
              ) : null}

              {!loading && payload.rows.length ? (
                payload.rows.map((row, rowIndex) => (
                  <section className="row-shell fade-slide" style={{ animationDelay: `${rowIndex * 60}ms` }} key={row.channel}>
                    <header className="row-head">
                      <h2 className="row-title">{row.title}</h2>
                      <span className="side-meta">{row.stories.length} clustered signals</span>
                    </header>

                    <div className="row-track">
                      {row.stories.map((story) => {
                        const isSelected = story.id === selectedStory?.id;
                        return (
                          <motion.article
                            key={story.id}
                            className="signal-card"
                            onClick={() => setSelectedStoryId(story.id)}
                            layoutId={`story-card-${story.id}`}
                            style={
                              isSelected
                                ? {
                                    borderColor: 'color-mix(in srgb, var(--accent) 55%, transparent)',
                                    boxShadow: '0 16px 48px rgba(0,0,0,0.34)'
                                  }
                                : undefined
                            }
                          >
                            <div className="signal-top">
                              <span>{story.sourceName}</span>
                              <span className="signal-score">{Math.round(story.rankScore)}</span>
                            </div>

                            <motion.h3 layoutId={`story-title-${story.cluster.id}`} className="signal-title">
                              {story.title}
                            </motion.h3>
                            <p className="signal-summary">{story.summary.slice(0, 140)}...</p>

                            <div className="signal-meta">
                              <span>{formatTimestamp(story.publishedAt, preferences.timezone)}</span>
                              <span>{story.cluster.storyIds.length} sources</span>
                            </div>
                          </motion.article>
                        );
                      })}
                    </div>
                  </section>
                ))
              ) : null}
            </motion.div>
          </AnimatePresence>
        </main>

        <aside className="glass detail-panel">
          {selectedStory ? (
            <motion.div layoutId={`story-card-${selectedStory.id}`}>
              <div className="detail-eyebrow">Active Signal</div>
              <motion.h2 layoutId={`story-title-${selectedStory.cluster.id}`} className="detail-title">
                {selectedStory.title}
              </motion.h2>

              <div className="detail-blurb">{selectedStory.summary}</div>

              <div className="inline-actions detail-block">
                <button className={`small-btn ${filedSet.has(selectedStory.id) ? 'primary' : ''}`} onClick={() => void toggleFiled(selectedStory.id)}>
                  <Bookmark size={14} /> {filedSet.has(selectedStory.id) ? 'Filed' : 'Save to Filed'}
                </button>

                <button
                  className="small-btn"
                  onClick={() => {
                    const entity = selectedStory.entities[0];
                    if (!entity) {
                      return;
                    }
                    const next = preferences.followedEntities.includes(entity)
                      ? preferences.followedEntities.filter((item) => item !== entity)
                      : [...preferences.followedEntities, entity];
                    void patchPreferences({ followedEntities: next });
                  }}
                >
                  <Bell size={14} /> Follow Entity
                </button>

                <button
                  className="small-btn"
                  onClick={() => {
                    const source = selectedStory.sourceName;
                    const next = preferences.mutedSources.includes(source)
                      ? preferences.mutedSources.filter((item) => item !== source)
                      : [...preferences.mutedSources, source];
                    void patchPreferences({ mutedSources: next }).then(() => refreshSignals(channel));
                  }}
                >
                  <VolumeX size={14} /> Mute Source
                </button>
              </div>

              <div className="detail-block">
                <div className="detail-label">Why this matters</div>
                {selectedStory.whyMatters.map((point, idx) => (
                  <p key={`${selectedStory.id}_${idx}`} className="why-item">
                    {point}
                  </p>
                ))}
              </div>

              <div className="detail-block">
                <div className="detail-label">Entities</div>
                <div className="entity-row">
                  {selectedStory.entities.map((entity) => (
                    <button
                      key={entity}
                      className="entity-pill"
                      onClick={() => {
                        setSearchTerm(entity);
                        void refreshSignals(channel, { q: entity });
                      }}
                    >
                      {entity}
                    </button>
                  ))}
                </div>
              </div>

              <div className="detail-block">
                <div className="detail-label">Cluster Sources</div>
                <div className="source-list">
                  {[selectedStory, ...selectedStory.additionalSources].map((story) => (
                    <a key={story.id} className="source-link" href={story.url} target="_blank" rel="noreferrer">
                      <span>
                        {story.sourceName} • {story.title}
                      </span>
                      <span>{relativeTime(story.publishedAt)}</span>
                    </a>
                  ))}
                </div>
              </div>

              <div className="detail-block">
                <div className="detail-label">Dossiers</div>
                <div className="inline-actions">
                  <button className="small-btn primary" onClick={createDossierFromSelected}>
                    Create Dossier
                  </button>
                  {dossiers.slice(0, 3).map((dossier) => (
                    <button key={dossier.id} className="small-btn" onClick={() => void addSelectedToDossier(dossier.id)}>
                      Add to {dossier.name}
                    </button>
                  ))}
                </div>

                {dossiers[0] ? (
                  <div style={{ marginTop: 10 }}>
                    <a
                      className="source-link"
                      href={`/api/dossiers/${dossiers[0].id}/export?format=markdown&userId=${encodeURIComponent(userId)}`}
                    >
                      <span>Export latest dossier as Markdown</span>
                      <span>Download</span>
                    </a>
                  </div>
                ) : null}
              </div>
            </motion.div>
          ) : (
            <div className="detail-blurb">No active signal selected.</div>
          )}
        </aside>
      </div>

      <CommandPalette
        open={commandOpen}
        query={commandQuery}
        onQueryChange={setCommandQuery}
        results={searchResults}
        onClose={() => setCommandOpen(false)}
        onSelect={onSelectCommandResult}
      />
    </LayoutGroup>
  );
}

'use client';

import { useEffect, useRef } from 'react';
import { SearchResult } from '@/lib/bonafied/types';

interface CommandPaletteProps {
  open: boolean;
  query: string;
  onQueryChange: (value: string) => void;
  results: SearchResult[];
  onClose: () => void;
  onSelect: (result: SearchResult) => void;
}

export function CommandPalette({
  open,
  query,
  onQueryChange,
  results,
  onClose,
  onSelect
}: CommandPaletteProps) {
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (open) {
      const id = window.setTimeout(() => inputRef.current?.focus(), 10);
      return () => window.clearTimeout(id);
    }
    return undefined;
  }, [open]);

  if (!open) {
    return null;
  }

  return (
    <div className="command-overlay" onClick={onClose}>
      <div className="command-shell" onClick={(event) => event.stopPropagation()}>
        <input
          ref={inputRef}
          className="command-input"
          placeholder="Search stories, entities, topics..."
          value={query}
          onChange={(event) => onQueryChange(event.target.value)}
        />

        <div className="command-list">
          {results.length ? (
            results.map((result) => (
              <button key={result.id} className="command-item" onClick={() => onSelect(result)}>
                <div>{result.title}</div>
                <div className="command-sub">
                  {result.type.toUpperCase()} • {result.subtitle}
                </div>
              </button>
            ))
          ) : (
            <div className="command-item" style={{ cursor: 'default' }}>
              <div>No matching signals</div>
              <div className="command-sub">Try source names, entities, or category terms.</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { getRedisClient } from '@/lib/bonafied/redis';

interface CacheEntry<T> {
  value: T;
  expiresAt: number;
}

const CACHE = new Map<string, CacheEntry<unknown>>();

export async function getCached<T>(key: string): Promise<T | null> {
  const redis = await getRedisClient();
  if (redis) {
    try {
      const raw = await redis.get(key);
      if (!raw) {
        return null;
      }
      return JSON.parse(raw) as T;
    } catch {
      // fall through to memory cache
    }
  }

  const hit = CACHE.get(key);
  if (!hit) {
    return null;
  }
  if (Date.now() > hit.expiresAt) {
    CACHE.delete(key);
    return null;
  }
  return hit.value as T;
}

export async function setCached<T>(key: string, value: T, ttlMs: number): Promise<void> {
  const redis = await getRedisClient();
  if (redis) {
    try {
      await redis.set(key, JSON.stringify(value), {
        PX: ttlMs
      });
      return;
    } catch {
      // fall through to memory cache
    }
  }

  CACHE.set(key, {
    value,
    expiresAt: Date.now() + ttlMs
  });
}

export async function invalidateByPrefix(prefix: string): Promise<void> {
  const redis = await getRedisClient();
  if (redis) {
    try {
      const scanner = redis.scanIterator({
        MATCH: `${prefix}*`,
        COUNT: 100
      });
      for await (const key of scanner) {
        await redis.del(key);
      }
    } catch {
      // continue into memory invalidation
    }
  }

  for (const key of CACHE.keys()) {
    if (key.startsWith(prefix)) {
      CACHE.delete(key);
    }
  }
}

import { CATEGORY_KEYWORDS } from '@/lib/bonafied/constants';
import { BonafiedCategory } from '@/lib/bonafied/types';

export function classifyCategory(text: string, fallback?: BonafiedCategory): BonafiedCategory {
  const haystack = text.toLowerCase();

  let bestCategory: BonafiedCategory = fallback || 'TECHNOLOGY';
  let bestScore = fallback ? 0.5 : 0;

  for (const [category, keywords] of Object.entries(CATEGORY_KEYWORDS) as Array<[
    BonafiedCategory,
    string[]
  ]>) {
    const score = keywords.reduce((acc, keyword) => acc + (haystack.includes(keyword) ? 1 : 0), 0);
    if (score > bestScore) {
      bestScore = score;
      bestCategory = category;
    }
  }

  return bestCategory;
}

import crypto from 'node:crypto';
import { SignalCluster, StoryRecord } from '@/lib/bonafied/types';
import { cosineSimilarity, jaccardSimilarity, normalizeTitle, tokenize } from '@/lib/bonafied/text';

interface ClusterState {
  cluster: SignalCluster;
  titleTokens: string[];
  stories: StoryRecord[];
}

const MIN_SIMILARITY = 0.62;

export function clusterStories(stories: StoryRecord[]): {
  clusters: SignalCluster[];
  stories: StoryRecord[];
} {
  const sorted = [...stories].sort(
    (a, b) => new Date(b.publishedAt).getTime() - new Date(a.publishedAt).getTime()
  );

  const states: ClusterState[] = [];
  const seenByUrl = new Set<string>();
  const deduped: StoryRecord[] = [];

  for (const story of sorted) {
    const canonical = canonicalizeUrl(story.url);
    if (seenByUrl.has(canonical)) {
      continue;
    }
    seenByUrl.add(canonical);
    deduped.push(story);

    const storyTokens = tokenize(story.title);
    let bestState: ClusterState | null = null;
    let bestScore = 0;

    for (const state of states) {
      if (state.cluster.category !== story.category) {
        continue;
      }

      const score = similarityScore(storyTokens, state.titleTokens);
      if (score > bestScore) {
        bestScore = score;
        bestState = state;
      }
    }

    if (bestState && bestScore >= MIN_SIMILARITY) {
      bestState.stories.push(story);
      bestState.cluster.storyIds.push(story.id);
      if (!bestState.cluster.sources.includes(story.sourceName)) {
        bestState.cluster.sources.push(story.sourceName);
      }
      for (const entity of story.entities) {
        if (!bestState.cluster.entities.includes(entity)) {
          bestState.cluster.entities.push(entity);
        }
      }
      if (new Date(story.publishedAt).getTime() > new Date(bestState.cluster.latestPublishedAt).getTime()) {
        bestState.cluster.latestPublishedAt = story.publishedAt;
      }
      if (story.rankScore > getPrimary(bestState.stories).rankScore) {
        bestState.cluster.primaryStoryId = story.id;
        bestState.cluster.headline = story.title;
      }
      bestState.titleTokens = tokenize(bestState.cluster.headline);
      continue;
    }

    const clusterId = `cluster_${crypto
      .createHash('sha1')
      .update(`${story.category}:${normalizeTitle(story.title)}`)
      .digest('hex')
      .slice(0, 12)}`;

    states.push({
      stories: [story],
      titleTokens: tokenize(story.title),
      cluster: {
        id: clusterId,
        category: story.category,
        headline: story.title,
        primaryStoryId: story.id,
        storyIds: [story.id],
        sources: [story.sourceName],
        entities: [...story.entities],
        score: story.rankScore,
        latestPublishedAt: story.publishedAt
      }
    });
  }

  const clusterMap = new Map<string, SignalCluster>();
  for (const state of states) {
    clusterMap.set(state.cluster.id, state.cluster);
  }

  return {
    clusters: [...clusterMap.values()],
    stories: deduped
  };
}

function getPrimary(stories: StoryRecord[]): StoryRecord {
  return [...stories].sort((a, b) => b.rankScore - a.rankScore)[0] || stories[0];
}

function canonicalizeUrl(value: string): string {
  try {
    const url = new URL(value);
    url.hash = '';
    url.search = '';
    return url.toString();
  } catch {
    return value;
  }
}

function similarityScore(leftTokens: string[], rightTokens: string[]): number {
  const jaccard = jaccardSimilarity(leftTokens, rightTokens);
  const cosine = cosineSimilarity(leftTokens, rightTokens);
  return jaccard * 0.46 + cosine * 0.54;
}

import { cleanText } from '@/lib/bonafied/text';

const KNOWN_ENTITIES = [
  'Apple',
  'Google',
  'Meta',
  'OpenAI',
  'Microsoft',
  'Amazon',
  'Spotify',
  'YouTube',
  'TikTok',
  'Substack',
  'Patreon',
  'Nvidia',
  'Reuters',
  'CNBC',
  'Billboard',
  'Podnews',
  'Universal',
  'Merlin',
  'Federal Reserve',
  'Wall Street Journal'
];

export function extractEntities(input: string): string[] {
  const text = cleanText(input);
  const found = new Set<string>();

  for (const entity of KNOWN_ENTITIES) {
    const expression = new RegExp(`\\b${escapeRegExp(entity)}\\b`, 'i');
    if (expression.test(text)) {
      found.add(entity);
    }
  }

  const properNounPairs = text.match(/\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,2}\b/g) || [];
  for (const candidate of properNounPairs) {
    if (candidate.length < 3 || candidate.length > 40) {
      continue;
    }
    if (/^(Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)$/i.test(candidate)) {
      continue;
    }
    found.add(candidate.trim());
    if (found.size > 16) {
      break;
    }
  }

  return [...found].slice(0, 14);
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

import crypto from 'node:crypto';
import Parser from 'rss-parser';
import { classifyCategory } from '@/lib/bonafied/classify';
import { clusterStories } from '@/lib/bonafied/cluster';
import { extractEntities } from '@/lib/bonafied/entity-extract';
import { scoreStory } from '@/lib/bonafied/rank';
import { mergeSignals, getFeeds } from '@/lib/bonafied/repository';
import { summarizeStory } from '@/lib/bonafied/summarize';
import { cleanText } from '@/lib/bonafied/text';
import { withinLast24Hours } from '@/lib/bonafied/time';
import { FeedConfig, IngestionResult, StoryRecord } from '@/lib/bonafied/types';

interface RssItem {
  title?: string;
  link?: string;
  pubDate?: string;
  isoDate?: string;
  contentSnippet?: string;
  content?: string;
  creator?: string;
  enclosure?: {
    url?: string;
    type?: string;
  };
  ['media:content']?: Array<{ $?: { url?: string } }>;
}

const parser = new Parser<Record<string, never>, RssItem>({
  timeout: 10_000,
  headers: {
    'User-Agent': 'BONAFIED/1.0'
  }
});

export async function ingestFeeds(): Promise<IngestionResult> {
  const feeds = (await getFeeds()).filter((feed) => feed.active);

  let fetchedFeeds = 0;
  let droppedForTime = 0;
  let droppedForMissingTimestamp = 0;
  let droppedForDupes = 0;

  const ingested: StoryRecord[] = [];

  for (const feed of feeds) {
    try {
      const parsed = await parser.parseURL(feed.url);
      fetchedFeeds += 1;

      for (const item of parsed.items || []) {
        const normalized = normalizeItem(item, feed);
        if (!normalized) {
          droppedForMissingTimestamp += 1;
          continue;
        }

        if (!withinLast24Hours(normalized.publishedAt)) {
          droppedForTime += 1;
          continue;
        }

        if (ingested.some((entry) => canonicalizeUrl(entry.url) === canonicalizeUrl(normalized.url))) {
          droppedForDupes += 1;
          continue;
        }

        ingested.push(normalized);
      }
    } catch {
      continue;
    }
  }

  const scored = ingested.map((story) => ({
    ...story,
    rankScore: scoreStory(story, 1)
  }));

  const clustered = clusterStories(scored);
  const rescored = clustered.stories.map((story) => {
    const cluster = clustered.clusters.find((item) => item.storyIds.includes(story.id));
    return {
      ...story,
      rankScore: scoreStory(story, cluster ? cluster.storyIds.length : 1)
    };
  });

  const merged = await mergeSignals(rescored);

  return {
    fetchedFeeds,
    ingestedStories: merged.inserted,
    droppedForTime,
    droppedForMissingTimestamp,
    droppedForDupes,
    clusteredSignals: merged.clusters,
    ingestedAt: new Date().toISOString()
  };
}

function normalizeItem(item: RssItem, feed: FeedConfig): StoryRecord | null {
  if (!item.title || !item.link) {
    return null;
  }

  const publishedAt = parsePublishedAt(item);
  if (!publishedAt) {
    return null;
  }

  const content = cleanText(item.contentSnippet || item.content || item.title);
  const category = classifyCategory(`${item.title} ${content}`, feed.category);
  const summary = summarizeStory(item.title, content);

  return {
    id: `story_${crypto
      .createHash('sha1')
      .update(`${item.link}:${publishedAt}`)
      .digest('hex')
      .slice(0, 14)}`,
    title: cleanText(item.title),
    url: item.link,
    sourceName: feed.name,
    sourceUrl: feed.url,
    publishedAt,
    category,
    content,
    imageUrl: item.enclosure?.url || item['media:content']?.[0]?.$?.url,
    summary: summary.brief,
    whyMatters: summary.whyMatters,
    entities: extractEntities(`${item.title}. ${content}`),
    rankScore: 0,
    verified: true,
    publishedTimestampKnown: true
  };
}

function parsePublishedAt(item: RssItem): string | null {
  const raw = item.isoDate || item.pubDate;
  if (!raw) {
    return null;
  }

  const timestamp = new Date(raw);
  if (Number.isNaN(timestamp.getTime())) {
    return null;
  }

  return timestamp.toISOString();
}

function canonicalizeUrl(value: string): string {
  try {
    const url = new URL(value);
    url.hash = '';
    url.search = '';
    return url.toString();
  } catch {
    return value;
  }
}

import nodemailer from 'nodemailer';

export async function sendMagicLinkEmail(email: string, token: string): Promise<void> {
  const host = process.env.SMTP_HOST;
  const port = process.env.SMTP_PORT ? Number(process.env.SMTP_PORT) : undefined;
  const user = process.env.SMTP_USER;
  const pass = process.env.SMTP_PASS;
  const from = process.env.SMTP_FROM || user;

  if (!host || !port || !user || !pass || !from) {
    return;
  }

  const transport = nodemailer.createTransport({
    host,
    port,
    secure: port === 465,
    auth: {
      user,
      pass
    }
  });

  const baseUrl = process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000';
  const link = `${baseUrl}/api/auth/verify?token=${encodeURIComponent(token)}`;

  await transport.sendMail({
    from,
    to: email,
    subject: 'BONAFIED magic link',
    text: `Use this sign-in link: ${link}`,
    html: `<p>Use this sign-in link:</p><p><a href="${link}">${link}</a></p>`
  });
}

